var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"Impossible…","TWN":"怎麼可能……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"어떻게 용의 힘을 잃고도 이전보다 더 강해질 수 있는 거죠?","JPN":"龍の力を失ったはずなのに、なぜ以前よりも強くなれたのですか？","ENG":"How could you grow even stronger upon losing the power of the Dragon?","TWN":"怎麼可能失去龍的力量後，卻變得比以前更強？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"분명 당신은 이제 평범한 인간일 뿐인데……!","JPN":"あなたはもはや平凡な人間に過ぎないはず……！","ENG":"Surely, you're nothing but an ordinary human by now…!","TWN":"現在的你應該只是個平凡人才對……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 반대로 생각해 보시면 어떤가요?","JPN":"ハハ、逆に考えてみてはいかがですか？","ENG":"Haha, have you ever considered it's the other way around?","TWN":"哈哈～你要不要逆向思考一下？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"인간이기에 이런 힘과 집념을 가질 수 있는 거라고.","JPN":"平凡な人間だからこそ、このような力と執念を持つことができるのです。","ENG":"Maybe I'm capable of such power and determination because I'm human.","TWN":"因為我是人，所以可以有這樣的力量和信念。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるさい！","ENG":"Silence!","TWN":"你閉嘴！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"고작 인간의 몸으로 이런 힘을 가질 수 있다면, 저와 동료들은 어째서 인간이기를 포기했어야 했던 겁니까?!","JPN":"たかが人間ごときの体でこんな力を持つことができるなら、どうして私と仲間たちは人間であることを諦めなければならなかったのですか？","ENG":"If it was possible to possess such powers as a mere human, why must my colleagues and I have forfeited our humanity?!","TWN":"若是區區血肉之軀可以有這樣的力量，我和伙伴們又何必要放棄做人？！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저에게 그렇게 물어 보셔도 답을 드릴 수는 없겠네요.","JPN":"僕にそんなことを聞かれても答えることはできませんね。","ENG":"I'm afraid I can't answer that question for you.","TWN":"就算你問我我也無法回答你。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"당신의 삶의 방식은 복수이고, 복수란 괴물로 바뀌어 가는 과정이니까요.","JPN":"あなたの生き方は復讐であり、復讐とは化け物に堕ちていく過程ですから。","ENG":"All I can say is that your way of living was revenge, and revenge turns people into monsters.","TWN":"你的生存之道是報仇，但在報仇的過程中會把你變成一個怪物！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 만약 당신들이 끝까지 인간으로 남으려고 했다면…….","JPN":"しかし、もしあなたたちが最後まで人間であろうとしたなら……","ENG":"If you guys decided to remain human until the very end…","TWN":"但如果你們堅持要以人類之姿活著……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금과는 다른 결과가 있었을지도 모르죠.","JPN":"今とは違う結果があったかもしれません。","ENG":"Perhaps there may have been different results.","TWN":"或許現在就不會是這樣的結果。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아니, 그런 일은 결단코 없었을 겁니다.","JPN":"いえ、そんなことは決してなかったはず。","ENG":"No. It would have never come to that.","TWN":"不，那種事絕對不會發生！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신과 마찬가지로, 저 역시 제 삶을 후회하지는 않으니까요.","JPN":"あなたと同じく、私も自分の人生を後悔していません。","ENG":"Because like you, I too have no regrets about my life.","TWN":"我和你一樣，我不會對我的決定而後悔！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래서 어쨌다는 거야?","JPN":"だからそれがどうしたっていうの？","ENG":"So what?","TWN":"所以你現在想怎樣？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신 계획은 실패했어! 이대로 계속 싸운다고 뭐가 달라질 것 같아?!","JPN":"あんたの計画は失敗した！　このまま戦っても何も変わらない！","ENG":"Your plan failed! You think fighting us will change anything?","TWN":"你的計畫失敗了！就算再打下去結果也不會改變！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"…No.","TWN":"不……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"계획은 틀어졌지만, 결국 변하는 것은 없습니다.","JPN":"計画は狂いましたが、結末が変わることはありません。","ENG":"You may have thwarted our initial plan, but this changes nothing.","TWN":"計畫出錯，但結果是一樣的！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자아, 늑대여. 어서 절 찌르고, 그 검에 제 피와 혼을 먹이십시오.","JPN":"さあ、狼よ。はやく私を刺して、その剣に私の血と魂を喰わせてください。","ENG":"Come now, Wolf. Stab me and feed your blade with my blood and soul.","TWN":"來吧！受詛咒的狼。快用那把劍刺進我的身體吸取我的血和靈魂！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무, 무슨 소리야? 지금 자살이라도 하겠다는 거야?","JPN":"な、何を言っているの？　今自殺でもするってこと？","ENG":"W-what are you talking about? You’re gonna commit suicide or something?","TWN":"你瘋了嗎？現在是要自殺的意思嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです。","ENG":"That's right.","TWN":"正是！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 자리에서 제가 승리할 수 없다면 제물을 당신이 아닌 저로 바꿀 뿐이지요.","JPN":"この場で私が勝利できないのなら、生贄をあなたではなく私に変えるだけです。","ENG":"If victory cannot be mine, I shall simply offer myself as the sacrifice instead of you.","TWN":"既然我打不贏你，那就乾脆把祭物換成是我！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신이 든 울브즈베인은 시련을 통해 성장하는 검.","JPN":"あなたの持つウルブズベインは試練によって成長する剣。","ENG":"The Wolvesbane you wield grows stronger with every trial.","TWN":"你手上那把狼之災禍是藉由考驗而成長的劍，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저를 제물로 삼아 더욱 강해지십시오.","JPN":"私を生贄にしてさらに強くなるといいでしょう。","ENG":"Use me as the sacrifice to grow stronger yet.","TWN":"就把我當作祭物，讓那把劍變得更強吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리하여 마침내 세상을 일그러뜨릴 만큼.","JPN":"そして、挙句は世界を歪めるほどに。","ENG":"Until the day you shall finally bring doom upon this world.","TWN":"強到可以毀滅世界！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어째서, 그렇게 뻔뻔스럽게……!","JPN":"どうして、そんなバカなことを……！","ENG":"How could you be so shameless!","TWN":"你臉皮還真厚……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇다면 이걸로 끝내 주겠어!","JPN":"ならこの剣で終わらせてやる！","ENG":"Fine, you asked for it!","TWN":"那我就如你所願吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"잠시만요, 미나 양.","JPN":"お待ちください、ミナさん。","ENG":"One moment, Mina.","TWN":"米娜等等！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"뭔가 이상해요. 기다리세요.","JPN":"何かがおかしいです、待ってください。","ENG":"Something seems off... Please wait.","TWN":"有點不對勁，你先等一下！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐가 날아온 거야?","JPN":"な、何が飛んできたの？","ENG":"W-what the heck was that?","TWN":"是…是什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하아, 참으로 실망스럽기 짝이 없구나.","JPN":"はあ、実に失望した。","ENG":"Fie, fie. How disappointing.","TWN":"哈，真是令人失望呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"황태자 전하?","JPN":"皇太子殿下？","ENG":"Your Highness?","TWN":"皇太子殿下？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너답지 않게 파격적인 연출을 준비했기에 나 역시 어울려 주었건만…….","JPN":"貴様らしくない破格的な演出を用意していたから、私も付き合ってやったのだが……","ENG":"I humored you since you've prepared such a dramatic presentation for a change…","TWN":"我想說你這次準備的劇本滿有趣的，還配合你演出……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"역시 천한 핏줄은 속일 수 없나 보군. 한심한 결말이야.","JPN":"やはり卑しい血筋は隠せないようだな。惨めな結末だ。","ENG":"But I suppose there's no fooling that lowborn bloodline of yours. What a pathetic conclusion this is.","TWN":"結果三流就是三流，這個結局根本就是爛尾。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하긴 제대로 된 무대라는 것을 구경한 적도 없는 너에게 기대를 한 내 잘못일지도 모르겠군.","JPN":"まあ、まともな舞台すら見たこともない貴様に期待した私が間違っていたかもしれないがな。","ENG":"Perhaps the fault is mine for getting my hopes up with thee, who has seen nary a single proper performance.","TWN":"不過想想也是，你這麼卑賤的身分，怎麼可能看過什麼好戲，只能怪我自己不該對你抱有期待。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하, 이 지경까지 와서도 절 모욕하고 싶으신 겁니까?","JPN":"殿下、こんな状況でも私を侮辱したいのですか？","ENG":"Does Your Highness wish to insult me to the very end?","TWN":"殿下，情況已經如此您還是要說這種話侮辱我嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"모욕? 대체 네 어디에 모욕을 할 만한 가치가 있다는 건가?","JPN":"侮辱？　貴様のどこに侮辱する価値があるというのだ？","ENG":"Insult thee? Pray tell me, what value would there be in insulting thee?","TWN":"侮辱？你覺得你有值得讓我侮辱的地方嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"처음에 넌 방주를 손에 넣기 위해 저 소년을 납치하자고 알렌을 설득했지.","JPN":"最初に貴様は箱舟を手に入れるため、あの少年を攫おうとアレンを説得した。","ENG":"Thou first persuaded Allen to abduct the lad so that we may gain control of the Ark.","TWN":"一開始是你說服艾倫說要拿到方舟就必須綁架那個少年，"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"용인으로 방주의 방어시스템을 쉽게 파괴할 수 있을 테고, 결국 성역의 힘을 이 땅에 더욱 깊이 뿌리내리게 하는 데 일조할 거라면서.","JPN":"龍人で箱舟の防御システムを簡単に破壊でき、\\nその結果聖域の力をこの地にさらに深く根付かせることができる、などとな。","ENG":"Thou said the Dragonoid would dispatch the Ark's defense system with ease, and the Ark would enable the power of sanctification to take deeper root in this land.","TWN":"還說龍人可以輕易破壞方舟的安全系統，對於聖域的力量更深植這塊土地會很有幫助。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경은 그 결정에 동의했고 결국 구원자의 맹세까지 들먹이며 레이를 끌어들였다.","JPN":"バーミンガム卿はその決定に同意し、救世主の誓いまで持ちかけてレイを巻き込んだ。","ENG":"Sir Allen agreed to that and dragged Ray in with that oath of the Savior nonsense.","TWN":"艾倫同意你的說法，還利用救贖者的誓言把雷伊也拖下水。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 저 어린 늑대가 미끼를 물자마자 너는 계획을 뒤로 미룬 채 복수에만 몰두했지.","JPN":"しかし、あの幼い狼が餌に飛びつくやいなや、貴様は計画を後回しにして復讐だけに没頭した。","ENG":"But the moment that Wolf Cub took the bait, thou focused solely on vengeance, without a care about the plan.","TWN":"但那隻幼狼一上鉤後，你就將計畫拋諸腦後，一心只想著報仇。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"심지어 네가 구원자라며 떠받드는 그 평민 놈에게도 비밀로 한 채.","JPN":"貴様が救世主と称えるあの平民にも秘密にしたまま。","ENG":"Thou even kept it a secret from that peasant lad thou worship as thy Savior.","TWN":"甚至還隱瞞你嘴上說尊敬的救贖者。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 거기까지는 제법 봐 줄 만했다만…….","JPN":"まあ、そこまでは大目に見てやるとしても。","ENG":"However, the show was enjoyable enough just yet…","TWN":"這些我都沒說話……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"복수를 실패하니 이제는 늑대에게 먹이로 삼아달라고 애원하는 지경이로군.","JPN":"復讐に失敗したら、今度は狼に餌にしてほしいと哀願しているだと？","ENG":"But now that thy plans for vengeance have failed, thou beg the Wolf to sup from thee?","TWN":"現在你報仇失敗，還哀求要狼把你當作獵物吞吃掉。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"대체 어디까지 추해질 셈이지?","JPN":"いったいどこまで墜ちるつもりだ？","ENG":"How low will thou go?","TWN":"你的尺度無下限嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"비극도 희극도, 그 본질은 결말이라는 과녁을 향해 날아가는 화살이다.","JPN":"悲劇も喜劇も、その本質は結末という的に向かって飛ぶ矢だ。","ENG":"In both comedy and tragedy, everything must reach its conclusion, like an arrow must reach its target.","TWN":"無論是喜劇或是悲劇，最重要的就是結局。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"신념도 없이 편의에 맞춰 결말을 이리저리 바꿔대면 화살은 빗나갈 뿐이지.","JPN":"信念もなく便宜によって結末を次々と変えれば、矢は外れるだけだ。","ENG":"Changing the conclusion on a whim, without conviction, will simply cause the arrow to miss the mark.","TWN":"身為一位編劇，若是不能堅持自己的想法，貪圖方便而任意更改結局，那難怪會爛尾囉！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 빗나간 화살에는 아무런 가치도 없다.","JPN":"そして、外れた矢には何の価値もない。","ENG":"There is no value in a missed arrow.","TWN":"而爛尾觀眾是不會買單的。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 무가치한 인생처럼 말이다. 루크레시아.","JPN":"貴様の無価値な人生と同じようにな、ルクレシア。","ENG":"Much like thy worthless life, Lucrecia.","TWN":"就像你的人生一樣，露可蕾西亞。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하, 저는 그저……!","JPN":"殿下、私はただ……！","ENG":"Your Highness, I was just-","TWN":"殿下，我只是……！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 좋다. 백성을 계도하는 것 또한 황족의 사명인 법이지.","JPN":"まあ、いい。民を啓導するのも皇族の使命である。","ENG":"Very well. 'Tis one of my many royal duties to shepherd my misguided subjects back to the right path.","TWN":"好吧！教導百姓也是身為皇族的使命之一。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 천박한 공연의 막은 내가 대신 내려 주도록 하마.","JPN":"この粗末な公演の幕は、私が代わりに下してやる。","ENG":"I shall draw the final curtain of this wretched play instead.","TWN":"就讓我來替這齣爛戲畫下句點吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 누구야, 저건?","JPN":"いったい誰なの、あれ？","ENG":"Who the heck is that?","TWN":"他到底是誰？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"갑자기 나타나서 혼자 신나게 떠들고 있잖아?","JPN":"急に現れて一人でペラペラ楽しそうだね。","ENG":"He appeared out of nowhere and started going all Shakespeare on us!","TWN":"突然出現自顧自地說什麼！"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"조심하세요, 미나 양.","JPN":"ご用心を、ミナさん。","ENG":"Be careful, Mina.","TWN":"米娜，你小心點。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저 남자. 지금까지 만난 그 어떤 적보다도 위험한 상대입니다.","JPN":"あの男、今までのどの敵よりも危険な相手です。","ENG":"That man... He is more dangerous than any enemy we've encountered thus far.","TWN":"那個男人比你至今遇到的任何一個敵人都還要危險。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐? 정말이야? 그 리플레이서 퀸이나 킹보다도?","JPN":"え？　本当に？　あのリプレイサー・クイーンやキングよりも？","ENG":"What? For real?! Even more than the Replacer Queen or King?","TWN":"你認真的嗎？他比克隆女皇、帝皇還強？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제 직감일 뿐이지만…… 비교도 할 수 없을 거에요.","JPN":"僕の直感にすぎませんが……比べものにならないでしょう。","ENG":"It's only my gut feeling… but yes. Beyond compare.","TWN":"雖然只是我的感覺……但他們應該是比不上。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"한심한 공연이었지만 그래도 넌 꽤나 분발해 주었다, 평민 소년.","JPN":"情けない公演だったが貴様はまあまあ好演したな、平民の少年よ。","ENG":"As pathetic as this play was, thou hast put thy best foot forward, peasant lad.","TWN":"雖然是齣爛戲，但年輕人你發揮得很不錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"오직 용이 되기 위해 달려온 혈족이 그 끝에서 인간으로 완성되는 결말을 선택하다니…….","JPN":"龍になるために生きてきた血族が、その最後に人間になる結末を選ぶとは……","ENG":"After generations upon generations striving to become a Dragon, thou chose to become complete as a mere human…","TWN":"一心想成為龍的家人，最後成為人的結局……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"정말, 모처럼 즐거웠다. 너에겐 내 경의를 받을 자격이 있어.","JPN":"久々に心から楽しめた。貴様は私の下賜を受ける資格がある。","ENG":"I haven't had this much fun in a long while. Thou deserve some of my respect.","TWN":"Bravo！精彩到我願意起立鼓掌。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니…… 나 또한 조금은 성의를 보여주마.","JPN":"よって……私も多少の誠意を見せてやろう。","ENG":"Thus… I shall treat thee in earnest, at least more than usual.","TWN":"所以……我決定拿出一點誠意來。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐야? 갑자기 자기 칼을 땅에 박아 넣다니, 항복이라도 하려는 건가?","JPN":"いきなり自分の剣を地面に刺してどうする気？　降参でもするの？","ENG":"What the... Why did he just stab the ground with his sword? Is he trying to surrender?","TWN":"幹嘛？突然把劍插在地上是要投降的意思嗎？"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"……지금 뭘 하시는 거죠?","JPN":"……今何をしているのですか？","ENG":"What… are you trying to do?","TWN":"……你這是什麼意思？"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 선조였던 구도자는 마룡으로 전락해 자신의 피를 숱한 후손들에게 뿌렸다.","JPN":"貴様の先祖だった求道者は魔龍に転落し、自らの血を多くの子孫に分け与えた。","ENG":"Thy ancestor, the Seeker, sprayed his blood across generations of descendents by becoming a Demon Dragon.","TWN":"你的祖先求道者墮落成魔龍後，將他的血分散給許多的後裔，"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_29"},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"조금이라도 바라밀에 이를 가능성을 높이기 위해서였지.","JPN":"少しでも波羅蜜に到達する可能性を高めるためにな。","ENG":"This was, of course, an effort to increase the chance of reaching Paramita.","TWN":"目的當然是希望可以多少提高圓滿波羅蜜的可能性。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_30"},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물론 그 직계 후손은 너였지만……. 다른 세계에도 용의 피를 이은 자들은 항상 존재했다.","JPN":"もちろん、その直系の子孫は貴様だったが……他の世界にも龍の血を継ぐ者は常に存在した。","ENG":"Although you may be the Seeker's direct descendent… There have always been others who inherited the Dragon Blood in other worlds as well.","TWN":"他的直系後裔只有你沒錯……但其他世界中也有龍血的繼承人。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_31"},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"설마……!","JPN":"まさか……！","ENG":"You mean…!","TWN":"難道……！"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우리 아르카데나 황실 역시 용혈의 가호를 받은 자들 중 하나.","JPN":"我がアルカデナ皇室も龍血の加護を受けた者の血統。","ENG":"The royal line of Arcadena has also been blessed with Dragon Blood.","TWN":"我們艾爾卡特納皇室就是繼承人之一。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_32"},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 황실은 오래 전부터 각지에 흩어진 용의 피를 이은 자들을 찾아 그들의 피를 수집해 왔다.","JPN":"そして皇室は古くから各地に散った龍の血を継ぐ者を探し出し、彼らの血を集めてきた。","ENG":"For long, the crown has sought those with Dragon Blood and collected their blood.","TWN":"而皇室從很久以前就開始尋找散落在各地的龍血繼承人，並且收集他們的血。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_33"},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 피에 잠든 힘을 연구하고 사용하기 위해서.","JPN":"その血に宿った力を研究し、使用するために。","ENG":"So that we may study and utilize the power that lay hidden within.","TWN":"為的是要研究並加以使用潛藏在血裡的力量。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_34"},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래서 그 나유빈이라는 자가 넘긴 너의 혈액 샘플로 바로 네 정체를 알아차릴 수 있었던 거지.","JPN":"よって、あのイチノセ・カオルという者が寄越した\\n貴様の血液サンプルで、すぐに貴様の正体に気づくことができたのだ。","ENG":"That is how we deduced thy true identity based on the blood sample provided by that Na Yubin fellow.","TWN":"所以我們才能在那個叫羅瑜斌的人把你的血交給我們當樣品時，立刻就發現你真正的身分。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_35"},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"……과연, 그랬군요.","JPN":"……なるほど、そうだったんですね。","ENG":"…I see.","TWN":"……果然是這樣。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 아쉽게 됐어요. 당신들이 만든 용인은 결국 파괴되었으니까요.","JPN":"しかし残念でしたね。あなたたちが作った龍人は破壊されましたから。","ENG":"Too bad for you, though. The Dragonoid you created was ultimately destroyed.","TWN":"但遺憾的是，你們創造的龍人失敗收場。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"착각하지 말도록. 그 용인을 만든 건 저 노예 출신의 천박한 힘이다.","JPN":"勘違いするな。その龍人を作ったのはあの奴隷出身の下卑た力だ。","ENG":"Do not be fooled. That Dragonoid was a crude creation of that lowly former slave.","TWN":"你不要搞錯，龍人是那個奴隸的主意，"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_36"},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"제국 황실은 용혈의 힘을 끌어내는 좀 더 세련된 방법을 찾아냈지.","JPN":"我が皇室は龍血の力を引き出す、より洗練された方法を発見した。","ENG":"The crown found a more sophisticated means of eliciting the power of Dragon Blood.","TWN":"帝國皇室已經找到更有效的方法，可以引出龍血的力量。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_37"},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"방법이라니……. 그 용혈은 저주의 촉매입니다.","JPN":"方法なんて……その龍血は呪いの触媒です。","ENG":"But that can't be… The Dragon Blood is a catalyst for a curse.","TWN":"什麼方法……那個龍血是詛咒的媒介。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아무리 당신이라도 함부로 사용한다면 이성을 유지할 수 없을 텐데요?","JPN":"いくらあなたでもむやみに使えば理性を保てなくなりますよ？","ENG":"Even you couldn't withstand its influence and retain your sanity if you used it.","TWN":"就算是你，任意使用也是有失去理智的可能。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 말대로다.","JPN":"そのとおりだ。","ENG":"It is as you say.","TWN":"你說的沒錯。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_38"},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 자신이 아닌 다른 사물을 통해 용혈을 사용하면 되지.","JPN":"ならば、自分ではない他の物に龍血を使えばいいのだ。","ENG":"Which is why we can use other objects to wield the blood instead.","TWN":"那就利用其他東西來代替自己使用龍血就好啦！"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_39"},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"번뇌도 고통도 이성도 없는 존재.","JPN":"煩悩も苦痛も理性もない存在。","ENG":"Beings without Kleshas, suffering, or even a corruptible mind.","TWN":"像是沒有煩惱、沒有痛苦、沒有理性的東西。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_40"},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예를 들어…… 검이라거나.","JPN":"例えば……剣はどうだ。","ENG":"For instance… a sword.","TWN":"譬如說……劍。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_41"},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"……뭐라고요?","JPN":"……なんですって？","ENG":"…What?","TWN":"……你說什麼？"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"용검 라르고여. 주인의 명에 따라 태초의 용혈을 마시고 네 칼날로 삼아라.","JPN":"龍剣ラルゴよ。主の命に従い、太古の龍血を飲み下し其方の刃と成せ。","ENG":"Dragonsword Largo. Obey thy master and drink of the first Dragon Blood. May it nurture thy new blade.","TWN":"龍劍聽令！立刻吸取原始龍血。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_42"},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서, 선배! 보고 있어?!","JPN":"せ、先輩！　見えてる！？","ENG":"S-Shiyoon! Are you seeing this?!","TWN":"前輩！你有看到嗎？"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석 칼이 선배의 피를 빨아들이고 있어!","JPN":"あいつの刀が先輩の血を吸い込んでる！","ENG":"That guy's sword is sucking up your blood!","TWN":"那傢伙的劍在吸你的血！"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"과연…… 저런 방법이 있었군요.","JPN":"なるほど……あんな方法があったんですね。","ENG":"I see… So that's how they do it.","TWN":"果然……還有那種方法。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"간신히 죽었다 살아났는데, 상황이 점점 더 나빠지는걸요.","JPN":"やっと生き返ってきたのに、状況がますます悪くなりましたね。","ENG":"I just barely came back from the dead… and things keep getting worse.","TWN":"我好不容易才從鬼門關爬回來，結果好像更糟糕。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자아, 시험해 보자. 소년.","JPN":"さあ、試してみようじゃないか少年よ。","ENG":"Now, let us put this to the test, lad.","TWN":"來吧！我們來測試看看。"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_43"},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네가 얻은 것이, 네가 버린 것보다 더 가치 있을지.","JPN":"貴様が得たものが、貴様が捨てたものより価値があるのかを。","ENG":"Let us see if what you gained was worth what you discarded.","TWN":"看看在你的得與失之間，哪個更有價值？"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_KNIGHT_C_EMPEROR_IN_TRAILER_44"},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나는, 아주 궁금하구나.","JPN":"私はとても興味深いのだ。","ENG":"I'm dying to find out.","TWN":"我個人非常好奇呢！"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"MAINSTREAM_7100013","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};